const argsSchema = [
  ['click-sleep-time', 5],
  ['find-sleep-time', 0],
  ['enable-logging', false],
  ['training-bet', 1],
  ['kill-all-scripts', false],
  ['no-deleting-remote-files', false],
  ['on-completion-script', null],
  ['on-completion-script-args', []],
];

let doc = eval("document");
let options;
let verbose = false;

export function autocomplete(data, args) {
  data.flags(argsSchema);
  const lastFlag = args.length > 1 ? args[args.length - 2] : null;
  if (["--on-completion-script"].includes(lastFlag))
    return data.scripts;
  return [];
}

async function main(ns) {
  options = getConfiguration(ns, argsSchema);
  if (!options) return;
  verbose = options['enable-logging'];
  if (verbose) tail(ns);
  else ns.disableLog("ALL");
  await startAutoRoulette(ns);
}

async function startAutoRoulette(ns) {
  await navigateToRoulette(ns);
  const clickElement = async (button) => await click(ns, button);
  if (options['kill-all-scripts'] && ns.ls("home", "Temp/").length > 0) {
    await killAllOtherScripts(ns, !options['no-deleting-remote-files']);
  }
  if (hasReachedCasinoLimit(ns))
    return await onCompletion(ns, false);
  const btnSaveGame = await findCasinoSaveButton((xpath, retries, customErrorMessage) =>
    findRequiredElement(ns, xpath, retries, customErrorMessage)
  );
  const playthrough = new RoulettePlaythrough();
  while (true) {
    if (await checkForKickedOut(tryfindElement, clickElement, ns) || hasReachedCasinoLimit(ns))
      return await onCompletion(ns, true);
    const wagerInput = await findRequiredElement(ns, "//input[@type='number']");
    const guess = playthrough.predictedWinner >= 0 ? playthrough.predictedWinner : 0;
    const bet = playthrough.predictedWinner >= 0 ?
      Math.min(1e7, Math.floor(ns.getPlayer().money * 0.9)) :
      options['training-bet'];
    if (bet <= 0) {
      log(ns, "WARNING: Not enough money to continue roulette automation. Reloading previous save...", true, 'warning');
      return await reloadGame(ns);
    }
    await setText(ns, wagerInput, `${bet}`);
    await click(ns, await findRequiredElement(ns, `//button[normalize-space(text())='${guess}']`));
    const result = await waitForRoundResult(ns, guess);
    if (result === null)
      return await onCompletion(ns, true);
    playthrough.addRound({ guess, result });
    if (result === guess && playthrough.predictedWinner >= 0)
      await saveCasinoGame(ns, clickElement, btnSaveGame);
    if (verbose)
      log(ns, `INFO: Roulette round guess=${guess}, result=${result}, next=${playthrough.predictedWinner}`, false);
  }
}

async function navigateToRoulette(ns) {
  let priorAttempts = 0;
  while (true) {
    if (priorAttempts > 0)
      await ns.sleep(1000);
    try {
      await ensureInAevum(ns,
        async (button) => await click(ns, button),
        async (xpath, retries, customErrorMessage) => await findRequiredElement(ns, xpath, retries, customErrorMessage));
      await navigateToCasino(ns,
        async (button) => await click(ns, button),
        async (xpath, retries, customErrorMessage) => await findRequiredElement(ns, xpath, retries, customErrorMessage));
      const stopButton = await tryfindElement(ns, "//button[normalize-space(text())='Stop playing']", 5);
      if (stopButton) await click(ns, stopButton);
      await openCasinoGame(async (button) => await click(ns, button),
        async (xpath, retries, customErrorMessage) => await findRequiredElement(ns, xpath, retries, customErrorMessage),
        'Play roulette');
      break;
    } catch (err) {
      if (++priorAttempts >= 5)
        throw new Error(`After ${priorAttempts} attempts, casino-roulette.js continues to catch unexpected errors ` +
          `while navigating to roulette. The final error was:\n  ${getErrorInfo(err)}`);
      tail(ns);
      verbose = true;
      log(ns, `WARNING: casino-roulette.js caught an unexpected error while navigating to roulette. ` +
        `Error was:\n${getErrorInfo(err)}\nWill try again (attempt ${priorAttempts} of 5)...`, false, 'warning');
    }
  }
  await findRequiredElement(ns, "//input[@type='number']", 25);
}

async function waitForRoundResult(ns, guess) {
  let sawPlaying = false;
  const buttonXpath = `//button[normalize-space(text())='${guess}']`;
  const clickElement = async (button) => await click(ns, button);
  for (let i = 0; i < 80; i++) {
    const guessButton = await tryfindElement(ns, buttonXpath, 1);
    const status = getStatusText();
    if (status === "playing") sawPlaying = true;
    if (sawPlaying && guessButton && !guessButton.disabled && status !== "playing") {
      const result = getCurrentNumber();
      if (result !== null) return result;
    }
    if (await checkForKickedOut(tryfindElement, clickElement, ns) || hasReachedCasinoLimit(ns)) return null;
    await ns.sleep(50);
  }
  if (hasReachedCasinoLimit(ns)) return null;
  throw new Error("Timed out waiting for roulette round result.");
}

function hasReachedCasinoLimit(ns) {
  return ns.getMoneySources().sinceInstall.casino > 10e9;
}

function getStatusText() {
  const statusNode = Array.from(doc.querySelectorAll("h4"))
    .find(node => {
      const text = (node.textContent || "").trim().toLowerCase();
      return text === "playing" || text.includes("won") || text.includes("lost");
    });
  return (statusNode?.textContent || "").trim().toLowerCase();
}

function getCurrentNumber() {
  const resultNode = Array.from(doc.querySelectorAll("h4"))
    .find(node => /^\d+(r|b)?$/i.test((node.textContent || "").trim()));
  if (!resultNode) return null;
  const text = resultNode.textContent.trim();
  const match = text.match(/^(\d+)/);
  return match ? Number(match[1]) : null;
}

async function onCompletion(ns, kickedOutAfterPlaying = true) {
  if (kickedOutAfterPlaying)
    log(ns, "SUCCESS: We've been kicked out of roulette.", true);
  else
    log(ns, "INFO: We appear to have been previously kicked out of roulette. Continuing without playing...", true);
  dismissFactionInvitationModal(ns);
  const completionScript = options['on-completion-script'];
  if (!completionScript) return;
  const completionArgs = options['on-completion-script-args'];
  log(ns, `INFO: casino-roulette.js shutting down and spawning ${completionScript}...`, false, 'info');
  ns.spawn(completionScript, {
    threads: 1,
    spawnDelay: 100,
  }, ...completionArgs);
}

function dismissFactionInvitationModal(ns) {
  const button = Array.from(doc.querySelectorAll("button"))
    .find(btn => btn.textContent?.trim() == "Decide later");
  if (!button) return false;
  button.click();
  log(ns, "INFO: Dismissed faction invitation modal before casino completion handoff.", false, 'info');
  return true;
}

async function reloadGame(ns) {
  let attempts = 0;
  let errMessage = '';
  while (attempts++ <= 5) {
    const win = eval("window");
    win.onbeforeunload = null;
    await ns.sleep(options['click-sleep-time']);
    if (attempts < 2)
      win.location = win.location;
    else if (attempts < 3)
      win.location.reload();
    else if (attempts < 4)
      win.location.reload(true);
    await ns.sleep(10000);
    errMessage = `casino-roulette.js asked the game to reload ${attempts} times, but it didn't.`;
    log(ns, `WARNING: ${errMessage} Trying again...`, true, 'warning');
  }
  throw new Error(`${errMessage} Giving up.`);
}

async function killAllOtherScripts(ns, removeRemoteFiles) {
  for (const script of ns.ps().filter(s => s.filename != ns.getScriptName()))
    ns.kill(script.pid);
  log(ns, `INFO: Killed other scripts running on home...`, true);

  const serversExceptHome = scanAllServers(ns).filter(s => s != "home");
  for (const host of serversExceptHome)
    ns.killall(host);
  log(ns, 'INFO: Killed all scripts running on other hosts...', true);

  if (removeRemoteFiles)
    log(ns, 'INFO: Skipping remote file cleanup in low-RAM roulette handoff mode.', true);
}

function scanAllServers(ns) {
  const discovered = new Set(["home"]);
  const queue = ["home"];
  for (const host of queue) {
    for (const next of ns.scan(host)) {
      if (discovered.has(next)) continue;
      discovered.add(next);
      queue.push(next);
    }
  }
  return [...discovered];
}

async function click(ns, button) {
  if (!button) throw new Error("click was called with null.");
  const sleepDelay = options['click-sleep-time'];
  if (sleepDelay > 0) await ns.sleep(sleepDelay);
  const fnOnClick = button[Object.keys(button)[1]]?.onClick;
  if (!fnOnClick) throw new Error(`Could not find onclick for button "${button.textContent?.trim() || "unknown"}".`);
  await fnOnClick({ isTrusted: true });
  if (sleepDelay > 0) await ns.sleep(sleepDelay);
}

async function setText(ns, input, text) {
  if (!input) throw new Error("setText was called with null.");
  const sleepDelay = options['click-sleep-time'];
  if (sleepDelay > 0) await ns.sleep(sleepDelay);
  const onChange = input[Object.keys(input)[1]]?.onChange;
  if (!onChange) throw new Error("Could not find onChange handler for roulette wager input.");
  await onChange({ isTrusted: true, target: { value: text } });
  if (sleepDelay > 0) await ns.sleep(sleepDelay);
}

async function findRequiredElement(ns, xpath, retries = 15, customErrorMessage = null) {
  return await internalfindWithRetry(ns, xpath, false, retries, customErrorMessage);
}

async function tryfindElement(ns, xpath, retries = 4) {
  return await internalfindWithRetry(ns, xpath, true, retries);
}

function internalFind(xpath) {
  return doc.evaluate(xpath, doc, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null).singleNodeValue;
}

async function internalfindWithRetry(ns, xpath, expectFailure, maxRetries, customErrorMessage = null) {
  try {
    if (options['find-sleep-time']) await ns.sleep(options['find-sleep-time']);
    let attempts = 0, retryDelayMs = 1;
    while (attempts++ <= maxRetries) {
      if (attempts > 1) await ns.sleep(retryDelayMs);
      retryDelayMs = Math.min(retryDelayMs * 2, 200);
      const found = internalFind(xpath);
      if (found !== null) return found;
    }
    if (!expectFailure) throw new Error(customErrorMessage ?? `Could not find element for xpath "${xpath}".`);
  } catch (e) {
    if (!expectFailure) throw e;
  }
  return null;
}

